parameters.code:
// Generate professional outreach email
const item = $input.first().json;
const domain = item.domain || 'example.com';
const niche = item.niche || 'technology';
const company = item.company || 'your company';
const action = item.action || 'buyer';

let subject, body, toEmail;

if (action === 'seller') {
  // Seller template
  const sellerName = item.seller_name || 'there';
  const firstName = sellerName.split(' ')[0];
  const price = item.asking_price || 'negotiable';
  toEmail = item.seller_email;

  subject = `I Have a Buyer for ${domain}`;

  body = `Hello ${firstName},\n\nI hope you're doing well.\n\nI'm a domain broker, and I currently have a qualified buyer who is actively looking for a domain in the ${niche} space. I believe your domain ${domain} could be the perfect match.\n\nI work on a commission basis — I only get paid when the deal closes. You set the price, I handle the negotiation and connect you with the buyer.\n\nFor complete safety and transparency, the transaction goes through Escrow.com, a trusted third-party service. The buyer deposits the funds, you transfer the domain, and once the buyer confirms receipt, the funds are released to you. No risk, no upfront fees.\n\nWould you be open to a quick discussion about this?\n\nThank you for your time.\n\nBest regards,\n\nKhalid Khan\nEmail: khalid.khan46571@gmail.com\nContact: 03019883536`;
} else {
  // Buyer template
  const buyerName = item.buyer_name || 'there';
  const firstName = buyerName.split(' ')[0];
  toEmail = item.buyer_email;

  subject = `Premium ${domain} — Perfect Fit for ${company}`;

  body = `Hello ${firstName},\n\nI hope you're doing well.\n\nI noticed that your company operates in the ${niche} space, and I wanted to reach out because I currently own the domain ${domain}, which I believe could be a strong fit for your brand.\n\nThe domain is short, memorable, and highly relevant to your business. It could help strengthen your online presence, improve brand recognition, and provide a premium digital asset for future growth.\n\nTo ensure a completely safe and transparent transaction, I use Escrow.com — a trusted third-party service that holds the payment until you receive full ownership of the domain. You only pay when you're satisfied, and I only get paid when the domain is successfully transferred to you. This protects both sides.\n\nIf this is something your team might be interested in, I'd be happy to discuss details and pricing.\n\nThank you for your time, and I look forward to hearing from you.\n\nBest regards,\n\nKhalid Khan\nEmail: khalid.khan46571@gmail.com\nContact: 03019883536`;
}

return [{
  json: {
    ...item,
    to_email: toEmail,
    email_subject: subject,
    email_body: body
  }
}];

